import{_ as e,o as l,c as a,a3 as n}from"./chunks/framework.DACwFHq9.js";const f=JSON.parse('{"title":"外观与壁纸","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/appearance.md","filePath":"user-guide/settings/appearance.md","lastUpdated":1778221347000}'),r={name:"user-guide/settings/appearance.md"};function s(d,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="外观与壁纸" tabindex="-1">外观与壁纸 <a class="header-anchor" href="#外观与壁纸" aria-label="Permalink to &quot;外观与壁纸&quot;">​</a></h1><blockquote><p>外观设置让 AIO Hub 的视觉风格完全由你掌控——从明暗主题到毛玻璃透明度，从动态壁纸到原生窗口特效。本篇将逐一介绍每个配置项的效果和用法。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在设置左侧导航栏中，点击「主题壁纸外观」选项卡。</li></ol><p>该面板采用<strong>双栏布局</strong>：左栏管理壁纸，右栏控制界面质感和窗口特效。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────┬────────────────────────────┐</span></span>
<span class="line"><span>│   壁纸管理（左栏）   │   界面质感（右栏上半）     │</span></span>
<span class="line"><span>│                      │   窗口特效（右栏下半）     │</span></span>
<span class="line"><span>├──────────────────────┴────────────────────────────┤</span></span>
<span class="line"><span>│   💡 小提示：所有调整都即时预览，无需保存。       │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="主题设置" tabindex="-1">主题设置 <a class="header-anchor" href="#主题设置" aria-label="Permalink to &quot;主题设置&quot;">​</a></h2><p>主题设置位于「通用设置」面板中，是调整视觉风格的第一步。</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>浅色 (Light)</strong></td><td style="text-align:left;">经典的明亮界面，适合白天或光线充足的环境</td></tr><tr><td style="text-align:left;"><strong>深色 (Dark)</strong></td><td style="text-align:left;">沉浸式的暗色界面，适合夜晚或保护视力</td></tr><tr><td style="text-align:left;"><strong>跟随系统 (Auto)</strong></td><td style="text-align:left;">根据操作系统的外观设置自动切换亮暗主题</td></tr></tbody></table><hr><h2 id="主题色设置" tabindex="-1">主题色设置 <a class="header-anchor" href="#主题色设置" aria-label="Permalink to &quot;主题色设置&quot;">​</a></h2><p>在「主题色配置」面板中，你可以定制应用的关键色彩。</p><table tabindex="0"><thead><tr><th style="text-align:left;">颜色类型</th><th style="text-align:left;">预设数量</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>主题色</strong></td><td style="text-align:left;">17 种</td><td style="text-align:left;">含 Element 标准色 + VOCALOID/UTAU 风格色</td></tr><tr><td style="text-align:left;"><strong>成功色</strong></td><td style="text-align:left;">11 种</td><td style="text-align:left;">成功状态提示颜色</td></tr><tr><td style="text-align:left;"><strong>警告色</strong></td><td style="text-align:left;">14 种</td><td style="text-align:left;">警告状态提示颜色</td></tr><tr><td style="text-align:left;"><strong>危险色</strong></td><td style="text-align:left;">14 种</td><td style="text-align:left;">危险/错误状态提示颜色</td></tr><tr><td style="text-align:left;"><strong>信息色</strong></td><td style="text-align:left;">6 种</td><td style="text-align:left;">普通信息提示颜色</td></tr></tbody></table><p>每种颜色都支持：</p><ul><li>从预设色板中选择</li><li>使用原生拾色器自定义 HEX 颜色</li><li>一键恢复默认值</li></ul><blockquote><p>当「主题色提取」开启时，主题色会自动被壁纸提取色覆盖，并显示「壁纸提取中」标签。</p></blockquote><hr><h2 id="壁纸管理" tabindex="-1">壁纸管理 <a class="header-anchor" href="#壁纸管理" aria-label="Permalink to &quot;壁纸管理&quot;">​</a></h2><p>壁纸管理位于「主题壁纸外观」面板的左栏。</p><h3 id="壁纸开关" tabindex="-1">壁纸开关 <a class="header-anchor" href="#壁纸开关" aria-label="Permalink to &quot;壁纸开关&quot;">​</a></h3><p>面板顶部的全局开关控制壁纸功能的启用/停用。关闭后壁纸和特效均不显示。</p><h3 id="壁纸模式" tabindex="-1">壁纸模式 <a class="header-anchor" href="#壁纸模式" aria-label="Permalink to &quot;壁纸模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>静态壁纸</strong></td><td style="text-align:left;">固定显示一张图片作为壁纸</td></tr><tr><td style="text-align:left;"><strong>轮播模式</strong></td><td style="text-align:left;">定时切换多张壁纸，支持随机/顺序播放</td></tr></tbody></table><p><strong>轮播模式</strong>下，你可以：</p><ul><li>设置轮播间隔（1-1440 分钟）</li><li>暂停/继续播放</li><li>随机播放或顺序播放，切换时重新洗牌</li><li>预览缩略图列表，点击即可切换到指定壁纸</li><li>通过控制栏按钮（上一张、暂停/继续、下一张）实时控制</li></ul><h3 id="壁纸来源" tabindex="-1">壁纸来源 <a class="header-anchor" href="#壁纸来源" aria-label="Permalink to &quot;壁纸来源&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">来源</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>内置壁纸</strong></td><td style="text-align:left;">从预设的壁纸网格中选择，点击即应用</td></tr><tr><td style="text-align:left;"><strong>自定义</strong></td><td style="text-align:left;">静态模式下选择单个图片文件；轮播模式下选择一个图片目录</td></tr></tbody></table><h3 id="填充模式" tabindex="-1">填充模式 <a class="header-anchor" href="#填充模式" aria-label="Permalink to &quot;填充模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">效果</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>覆盖 (Cover)</strong></td><td style="text-align:left;">等比例缩放填满全屏，可能裁剪边缘</td><td style="text-align:left;">最常用，适合大多数图片</td></tr><tr><td style="text-align:left;"><strong>包含 (Contain)</strong></td><td style="text-align:left;">完整显示整张图片，留黑边</td><td style="text-align:left;">需要看到完整图片内容</td></tr><tr><td style="text-align:left;"><strong>拉伸 (Fill)</strong></td><td style="text-align:left;">拉伸填满，可能变形</td><td style="text-align:left;">适合无缝纹理</td></tr><tr><td style="text-align:left;"><strong>平铺 (Tile)</strong></td><td style="text-align:left;">重复拼接所有图片</td><td style="text-align:left;">适合小尺寸图案或纹理</td></tr></tbody></table><p><strong>拼贴模式</strong>提供额外参数调整：</p><ul><li><strong>缩放</strong>：0.1x - 3x，控制平铺单元的放大/缩小</li><li><strong>旋转</strong>：0° - 360°，每个单元的旋转角度</li><li><strong>水平翻转 / 垂直翻转</strong></li></ul><h3 id="清除壁纸" tabindex="-1">清除壁纸 <a class="header-anchor" href="#清除壁纸" aria-label="Permalink to &quot;清除壁纸&quot;">​</a></h3><p>点击「清除壁纸」按钮可以移除当前设置的壁纸，恢复无壁纸状态。</p><blockquote><p>壁纸设置界面左上角有<strong>预览区域</strong>，实时显示当前壁纸的效果。点击预览区域可以<strong>查看大图</strong>。</p></blockquote><hr><h2 id="界面质感" tabindex="-1">界面质感 <a class="header-anchor" href="#界面质感" aria-label="Permalink to &quot;界面质感&quot;">​</a></h2><p>界面质感部分通过「UI 特效」全局开关控制。关闭后，所有透明度与模糊效果都被禁用，界面回到纯色风格。</p><blockquote><p>💡 <strong>禁用 UI 特效可以略微提高性能</strong>，特别是低配置设备或集显机型上。</p></blockquote><h3 id="ui-基础不透明度" tabindex="-1">UI 基础不透明度 <a class="header-anchor" href="#ui-基础不透明度" aria-label="Permalink to &quot;UI 基础不透明度&quot;">​</a></h3><p>滑块控制（0 - 1，步长 0.05），影响所有 UI 元素的整体透明度。值越小，壁纸透出的越多。</p><h3 id="分离窗口不透明度-悬浮化的组件" tabindex="-1">分离窗口不透明度（悬浮化的组件） <a class="header-anchor" href="#分离窗口不透明度-悬浮化的组件" aria-label="Permalink to &quot;分离窗口不透明度（悬浮化的组件）&quot;">​</a></h3><p>滑块控制分离出去的悬浮窗口的内部元素透明度（默认 0.95），与主窗口独立设置。</p><blockquote><p>⚠️ <strong>重要提示</strong>：在主窗口中，由于底层有壁纸和窗口背景色叠加，UI 不透明度可以调得非常低（如 0.1）依然能看清。但<strong>分离的悬浮组件窗口</strong>底层通常是完全透明的，如果此值设置过低，窗口内的文本和图标将因失去背景托底而变得难以辨认。建议保持在 0.8 - 1.0 之间。</p></blockquote><h3 id="背景色叠加" tabindex="-1">背景色叠加 <a class="header-anchor" href="#背景色叠加" aria-label="Permalink to &quot;背景色叠加&quot;">​</a></h3><p>背景色叠加是毛玻璃效果的关键补充。开启后，在壁纸之上叠加一层颜色，通过混合模式产生丰富的视觉效果。</p><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>叠加颜色</strong></td><td style="text-align:left;">选择颜色，或使用**屏幕吸色（EyeDropper API）**取色，或从当前壁纸自动提取</td></tr><tr><td style="text-align:left;"><strong>自动从壁纸提取颜色</strong></td><td style="text-align:left;">开启后，切换壁纸时自动提取主色调用于叠加</td></tr><tr><td style="text-align:left;"><strong>混合模式</strong></td><td style="text-align:left;">支持 16 种 CSS 混合模式，用于定义背景色与壁纸的融合方式（详见下表）</td></tr><tr><td style="text-align:left;"><strong>叠加不透明度</strong></td><td style="text-align:left;">控制叠加层的透明程度</td></tr></tbody></table><h4 id="支持的混合模式" tabindex="-1">支持的混合模式 <a class="header-anchor" href="#支持的混合模式" aria-label="Permalink to &quot;支持的混合模式&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">说明</th><th style="text-align:left;">模式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>normal</strong></td><td style="text-align:left;">正常</td><td style="text-align:left;"><strong>soft-light</strong></td><td style="text-align:left;">柔光</td></tr><tr><td style="text-align:left;"><strong>multiply</strong></td><td style="text-align:left;">正片叠底</td><td style="text-align:left;"><strong>difference</strong></td><td style="text-align:left;">差值</td></tr><tr><td style="text-align:left;"><strong>screen</strong></td><td style="text-align:left;">滤色</td><td style="text-align:left;"><strong>exclusion</strong></td><td style="text-align:left;">排除</td></tr><tr><td style="text-align:left;"><strong>overlay</strong></td><td style="text-align:left;">叠加</td><td style="text-align:left;"><strong>hue</strong></td><td style="text-align:left;">色相</td></tr><tr><td style="text-align:left;"><strong>darken</strong></td><td style="text-align:left;">变暗</td><td style="text-align:left;"><strong>saturation</strong></td><td style="text-align:left;">饱和度</td></tr><tr><td style="text-align:left;"><strong>lighten</strong></td><td style="text-align:left;">变亮</td><td style="text-align:left;"><strong>color</strong></td><td style="text-align:left;">颜色</td></tr><tr><td style="text-align:left;"><strong>color-dodge</strong></td><td style="text-align:left;">颜色减淡</td><td style="text-align:left;"><strong>luminosity</strong></td><td style="text-align:left;">亮度</td></tr><tr><td style="text-align:left;"><strong>color-burn</strong></td><td style="text-align:left;">颜色加深</td><td style="text-align:left;"><strong>hard-light</strong></td><td style="text-align:left;">强光</td></tr></tbody></table><h3 id="主题色提取" tabindex="-1">主题色提取 <a class="header-anchor" href="#主题色提取" aria-label="Permalink to &quot;主题色提取&quot;">​</a></h3><p>此功能独立于背景色叠加。开启后，当切换壁纸时，系统会自动提取壁纸中的亮眼颜色，<strong>应用到全局主题色</strong>（按钮、选中态、链接等）。</p><p>四种提取策略：</p><table tabindex="0"><thead><tr><th style="text-align:left;">策略</th><th style="text-align:left;">效果</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>柔和 (Muted)</strong> — 推荐</td><td style="text-align:left;">提取最温和、不刺眼的颜色，适合日常使用</td></tr><tr><td style="text-align:left;"><strong>鲜艳 (Vibrant)</strong></td><td style="text-align:left;">提取最鲜艳的颜色，更具活力</td></tr><tr><td style="text-align:left;"><strong>亮部鲜艳 (Light Vibrant)</strong></td><td style="text-align:left;">从图片亮部区域提取鲜艳色</td></tr><tr><td style="text-align:left;"><strong>暗部鲜艳 (Dark Vibrant)</strong></td><td style="text-align:left;">从图片暗部区域提取鲜艳色</td></tr></tbody></table><blockquote><p>可以随时在 <strong>主题色设置</strong> 面板中看到当前提取的颜色预览。</p></blockquote><h3 id="壁纸不透明度" tabindex="-1">壁纸不透明度 <a class="header-anchor" href="#壁纸不透明度" aria-label="Permalink to &quot;壁纸不透明度&quot;">​</a></h3><p>独立控制壁纸层的透明度（0 - 1）。降低此值可以让壁纸更淡，使背景色叠加层或纯色背景更明显。</p><h3 id="ui-模糊-毛玻璃" tabindex="-1">UI 模糊（毛玻璃） <a class="header-anchor" href="#ui-模糊-毛玻璃" aria-label="Permalink to &quot;UI 模糊（毛玻璃）&quot;">​</a></h3><p>全局开关 + 强度滑块（0-50px）。开启后，所有 UI 卡片、面板、对话框都会应用毛玻璃模糊效果，透出壁纸。</p><h3 id="边线" tabindex="-1">边线 <a class="header-anchor" href="#边线" aria-label="Permalink to &quot;边线&quot;">​</a></h3><ul><li><strong>边线不透明度</strong>（0 - 1）：控制 UI 元素边框线的透明度</li><li><strong>边线宽度</strong>（0 - 5px）：控制边框线的粗细</li></ul><blockquote><p>将边线不透明度设为 0 可隐藏所有边框，获得更纯的毛玻璃效果。</p></blockquote><h3 id="代码块背景不透明度" tabindex="-1">代码块背景不透明度 <a class="header-anchor" href="#代码块背景不透明度" aria-label="Permalink to &quot;代码块背景不透明度&quot;">​</a></h3><p>控制代码编辑器（如 CSS 覆盖编辑器、LLM 返回的代码块）的背景透明度，使其更好地融入整体风格而不是一块&quot;死沉&quot;的实色。</p><hr><h2 id="窗口特效-实验性" tabindex="-1">窗口特效（实验性） <a class="header-anchor" href="#窗口特效-实验性" aria-label="Permalink to &quot;窗口特效（实验性）&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">注意</p><p>窗口特效依赖于操作系统的原生能力，目前仅在 <strong>Windows 10+</strong> 和 <strong>macOS</strong> 上可用。Linux 系统因兼容性问题会<strong>自动禁用</strong>并显示提示。</p></div><table tabindex="0"><thead><tr><th style="text-align:left;">特效</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>无</strong></td><td style="text-align:left;">不启用任何窗口原生特效</td></tr><tr><td style="text-align:left;"><strong>模糊 (Blur)</strong></td><td style="text-align:left;">Windows 窗口背景模糊</td></tr><tr><td style="text-align:left;"><strong>亚克力 (Acrylic)</strong></td><td style="text-align:left;">Windows 10+ 亚克力效果，更丰富的模糊与纹理混合</td></tr><tr><td style="text-align:left;"><strong>云母 (Mica)</strong></td><td style="text-align:left;">Windows 11 云母材质效果，性能更好的透明背景</td></tr></tbody></table><h3 id="窗口背景不透明度" tabindex="-1">窗口背景不透明度 <a class="header-anchor" href="#窗口背景不透明度" aria-label="Permalink to &quot;窗口背景不透明度&quot;">​</a></h3><p>独立开关 + 滑块控制。需要开启窗口特效且该开关启用才生效。降低此值以透出桌面或窗口后的内容。</p><h3 id="窗口阴影" tabindex="-1">窗口阴影 <a class="header-anchor" href="#窗口阴影" aria-label="Permalink to &quot;窗口阴影&quot;">​</a></h3><p>控制窗口是否显示阴影效果。关闭后可获得更简洁的视觉风格。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-调整设置后如何恢复默认" tabindex="-1">Q：调整设置后如何恢复默认？ <a class="header-anchor" href="#q-调整设置后如何恢复默认" aria-label="Permalink to &quot;Q：调整设置后如何恢复默认？&quot;">​</a></h3><p>每个滑块和开关都可以手动调回默认值。主题色部分提供「重置为默认」按钮，壁纸可以点击「清除壁纸」。</p><h3 id="q-为什么我的窗口特效选项是灰色的" tabindex="-1">Q：为什么我的窗口特效选项是灰色的？ <a class="header-anchor" href="#q-为什么我的窗口特效选项是灰色的" aria-label="Permalink to &quot;Q：为什么我的窗口特效选项是灰色的？&quot;">​</a></h3><p>如果你是 Linux 用户，窗口特效因兼容性问题被自动禁用。Windows 用户请确认操作系统版本 ≥ Windows 10。</p><h3 id="q-毛玻璃效果导致性能下降怎么办" tabindex="-1">Q：毛玻璃效果导致性能下降怎么办？ <a class="header-anchor" href="#q-毛玻璃效果导致性能下降怎么办" aria-label="Permalink to &quot;Q：毛玻璃效果导致性能下降怎么办？&quot;">​</a></h3><p>关闭「UI 特效」全局开关即可禁用所有透明度与模糊效果，界面回到纯色风格，性能开销降到最低。</p><h3 id="q-如何让应用看起来完全透明" tabindex="-1">Q：如何让应用看起来完全透明？ <a class="header-anchor" href="#q-如何让应用看起来完全透明" aria-label="Permalink to &quot;Q：如何让应用看起来完全透明？&quot;">​</a></h3><p>可以尝试以下组合：</p><ol><li>开启壁纸</li><li>开启「UI 特效」</li><li>将「UI 基础不透明度」调到较低值</li><li>开启「UI 模糊」</li><li>在窗口特效中选择「亚克力」或「云母」</li><li>开启窗口背景不透明度并调低</li></ol><hr><blockquote><p><strong>下一步</strong>：配置完外观后，前往 <a href="./llm-service">AI 服务配置</a> 设置你的 LLM 服务，开始使用 AI 对话功能。</p></blockquote>`,84)])])}const y=e(r,[["render",s]]);export{f as __pageData,y as default};
